"use strict";parserFactory.register("worldnovel.online",()=>new WorldnovelOnlineParser);class WorldnovelOnlineParser extends Parser{constructor(){super()}async getChapterUrls(e,t){let r=[],n=e.body.getAttribute("attr"),o=[...e.querySelectorAll("div[data-paged]")].length;for(let e=1;e<=o;++e){let o="https://www.worldnovel.online/wp-json/novel-id/v1/dapatkan_chapter_dengan_novel?category="+n+"&perpage=100&order=ASC&paged="+e,l=(await HttpClient.fetchJson(o)).json.map(this.jsonToChapter);t.showTocProgress(l),r=r.concat(l)}return r}jsonToChapter(e){return{sourceUrl:e.permalink,title:e.post_title,newArc:null}}findContent(e){return e.querySelector("div#soop")}extractTitleImpl(e){return e.querySelector("li.breadcrumb-item.active")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".code-block, ins, .chapternav, a[href='javascript:void(0)']"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("h3.post-title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"main#main div.container")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div#maintab div.post-content")]}}